using System.Collections;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Objecto revelável pelo Sonar (P5 — SonarAbility): segredos, paredes falsas,
/// itens escondidos. Dois modos:
///
/// - Com "revealTarget": o GameObject indicado é activado durante a revelação
///   (ex: contorno/realce/ícone) e desactivado no fim.
/// - Sem "revealTarget": o próprio SpriteRenderer alterna entre "hiddenAlpha"
///   (escondido) e alpha 1 (revelado).
/// </summary>
public class SonarRevealable : MonoBehaviour
{
    [Header("Modo A — GameObject de realce (opcional)")]
    [Tooltip("GameObject activado enquanto revelado (contorno, brilho, ícone). Se vazio, usa o modo B (alpha do sprite).")]
    public GameObject revealTarget;

    [Header("Modo B — Alpha do sprite")]
    [Tooltip("Alpha do sprite enquanto NÃO revelado (0 = invisível).")]
    [Range(0f, 1f)] public float hiddenAlpha = 0f;

    [SerializeField] private SpriteRenderer spriteRenderer;

    [Header("Eventos")]
    public UnityEvent onRevealed;
    public UnityEvent onHidden;

    private Coroutine _routine;

    /// <summary>true enquanto está revelado.</summary>
    public bool IsRevealed { get; private set; }

    private void Awake()
    {
        if (spriteRenderer == null) spriteRenderer = GetComponent<SpriteRenderer>();
        ApplyState(false);
    }

    /// <summary>Revela durante "duration" segundos (chamado por SonarAbility; renovável).</summary>
    public void Reveal(float duration)
    {
        if (_routine != null) StopCoroutine(_routine);
        _routine = StartCoroutine(RevealRoutine(duration));
    }

    private IEnumerator RevealRoutine(float duration)
    {
        if (!IsRevealed)
        {
            IsRevealed = true;
            ApplyState(true);
            onRevealed?.Invoke();
        }

        yield return new WaitForSeconds(duration);

        IsRevealed = false;
        ApplyState(false);
        onHidden?.Invoke();
        _routine = null;
    }

    private void ApplyState(bool revealed)
    {
        if (revealTarget != null)
        {
            revealTarget.SetActive(revealed);
            return;
        }

        if (spriteRenderer == null) return;

        var color = spriteRenderer.color;
        color.a = revealed ? 1f : hiddenAlpha;
        spriteRenderer.color = color;
    }
}
